                            <span className="text-[10px] font-black uppercase tracking-widest text-indigo-300">Live Strategy</span>
                          </div>
                          <div className="p-6 space-y-4">
                            <div className="bg-indigo-50 p-4 rounded-2xl text-indigo-900 text-sm font-bold italic">
                              “{plan.strategy_summary}”
                            </div>
                            <div className="grid grid-cols-1 gap-3">
                              {plan.items.map(item => (
                                <div key={item.id} className="flex items-center gap-4 p-4 bg-slate-50 rounded-2xl border border-slate-100 group transition-all">
                                  <div className={`w-3 h-3 rounded-full shrink-0 ${item.action === 'buy' ? 'bg-rose-500' : item.action === 'sell' ? 'bg-emerald-500' : 'bg-slate-300'}`} />
                                  <div className="flex-1">
                                    <div className="flex items-center gap-2">
                                      <span className="font-black text-slate-800">{item.symbol}</span>
                                      <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase ${item.action === 'buy' ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>{item.action}</span>
                                    </div>
                                    <div className="text-xs text-slate-500 font-medium">{item.reason}</div>
                                  </div>
                                  <div className="text-right">
                                    <div className="text-sm font-black text-slate-800">{item.price_target || '--'}</div>
                                    <div className="text-[9px] font-bold text-slate-400 uppercase">Target Price</div>
                                  </div>
                                </div>
                              ))}
                            </div>
                          </div>
                        </div>
                      ))
                    )}
                  </div>
                ) : (
                  <div className="py-40 flex flex-col items-center justify-center text-slate-200">
                    <Loader2 className="w-16 h-16 animate-spin-slow mb-6" />
                    <p className="text-2xl font-black">等待深度审计指令</p>
                  </div>
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
