import { ModelProvider, AnalysisResult, UserSettings, MarketType, HoldingsSnapshot, HoldingItemDetailed, JournalEntry, DailyTradingPlan, PlanItem } from '../types';
import { analyzeWithLLM } from '../services/llmAdapter';
import { parseBrokerageScreenshot, extractTradingPlan } from '../services/geminiService';
import { Upload, Loader2, Save, History, Trash2, Camera, Edit2, Check, X, FileJson, TrendingUp, AlertTriangle, ListTodo, Calendar, Download, FileText, ChevronRight, LayoutGrid, CheckCircle2, XCircle, MoreHorizontal, Info, Target, ShieldCheck, Activity, ArrowRightCircle } from 'lucide-react';
