interface HoldingsReviewProps {
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: UserSettings;
  onOpenSettings?: () => void;
}

export const HoldingsReview: React.FC<HoldingsReviewProps> = ({
  currentModel,
  currentMarket,
  settings,
  onOpenSettings
}) => {
  const [snapshot, setSnapshot] = useState<HoldingsSnapshot>({
    totalAssets: 0,
    positionRatio: 0, 
    date: new Date().toISOString().split('T')[0],
    holdings: []
  });

  const [journal, setJournal] = useState<JournalEntry[]>(() => {
    const saved = localStorage.getItem('qm_journal');
    return saved ? JSON.parse(saved) : [];
  });

  const [tradingPlans, setTradingPlans] = useState<DailyTradingPlan[]>(() => {
    const saved = localStorage.getItem('qm_trading_plans');
    return saved ? JSON.parse(saved) : [];
  });

  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [parsing, setParsing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'report' | 'plans'>('report');
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [loadingPhase, setLoadingPhase] = useState("");

  // Editing state
  const [editingIndex, setEditingIndex] = useState<number | null>(null);
  const [editForm, setEditForm] = useState<HoldingItemDetailed | null>(null);

  useEffect(() => {
    localStorage.setItem('qm_journal', JSON.stringify(journal));
  }, [journal]);

  useEffect(() => {
    localStorage.setItem('qm_trading_plans', JSON.stringify(tradingPlans));
  }, [tradingPlans]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setParsing(true);
    setError(null);

    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = (reader.result as string).split(',')[1];
        try {
          const parsedData = await parseBrokerageScreenshot(base64String, settings.geminiKey);

          // 视觉修正：如果是负数成本或盈亏，确保在 UI 中正确显示
          setSnapshot({
            ...parsedData,
            totalAssets: parsedData.totalAssets || 0,
            date: new Date().toISOString().split('T')[0]
          });
        } catch (err: any) {
          setError("识别失败：无法解析该截图内容。请尝试手动录入或更换更清晰的截图。");
        } finally {
          setParsing(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setParsing(false);
      setError("文件读取失败");
    }
  };

  const handleAnalyze = async () => {
    if (snapshot.holdings.length === 0) {
      setError("请先上传持仓截图或手动录入标的");
      return;
    }

    setLoading(true);
    setAnalysisResult(null);
    setError(null);
    setLoadingPhase("正在联网检索最新行情与 L2 资金流向...");

    const lastEntry = journal[0]; 
    const contextHistory = lastEntry 
      ? `[历史基准] 上次复盘总资产 ¥${lastEntry.snapshot.totalAssets}。`
      : "首次复盘，无历史基准。";

    const prompt = `
      作为顶级 A 股量化顾问，请对我的持仓进行【连续性深度审计】。

      ${contextHistory}

      === 当前持仓详情 (总资产: ¥${snapshot.totalAssets}) ===
      ${snapshot.holdings.map(h => `- ${h.name} (${h.code}): 成本 ${h.costPrice}, 现价 ${h.currentPrice}, 盈亏 ${h.profitRate}`).join('\n')}

      【要求】:
      1. 必须包含具体的【支撑位】与【止损建议】。
      2. 如果出现盈亏大幅波动，请结合今日大盘解释原因。
      3. 必须包含一个明确的【实战交易指令】章节。

      请使用 Markdown 格式输出，标题请使用 ## 开头。
    `;

    try {
      setTimeout(() => setLoadingPhase("正在进行个股支撑/压力位计算..."), 3000);
      setTimeout(() => setLoadingPhase("正在根据资金热度生成实战指令..."), 6000);

      const result = await analyzeWithLLM(currentModel, prompt, true, settings, false, 'day', undefined, currentMarket);

      if (!result || !result.content) {
        throw new Error("AI 返回内容为空，请重试。");
      }

      setAnalysisResult(result);
      setActiveTab('report');
    } catch (err: any) {
      setError(err.message || "分析请求超时或被拦截，请检查网络环境。");
    } finally {
      setLoading(false);
      setLoadingPhase("");
    }
  };

  const generateTradingPlan = async () => {
    if (!analysisResult) return;
    setLoading(true);
    setLoadingPhase("正在提取核心操作点并生成计划表...");
    try {
      const plan = await extractTradingPlan(analysisResult.content, settings.geminiKey);
      const newPlan: DailyTradingPlan = {
        id: crypto.randomUUID(),
        target_date: new Date(Date.now() + 86400000).toISOString().split('T')[0],
        created_at: Date.now(),
        items: plan.items,
        strategy_summary: plan.summary
      };
      setTradingPlans([newPlan, ...tradingPlans]);
      setActiveTab('plans');
    } catch (err) {
      setError("生成交易计划失败");
    } finally {
      setLoading(false);
      setLoadingPhase("");
    }
  };

  // 鲁棒性解析器：即使没有 ## 标题也能正常渲染
  const renderReportContent = (content: string) => {
    if (!content) return <div className="p-8 text-slate-400">无内容显示</div>;

    // 兼容多种标题格式
    const sections = content.split(/^(?:##|###)\s+/gm).filter(Boolean);

    if (sections.length <= 1) {
      return (
        <div className="p-8 bg-white rounded-2xl border border-slate-200">
          <div className="prose prose-slate max-w-none text-slate-600 leading-relaxed whitespace-pre-wrap">
            {content}
          </div>
        </div>
      );
    }

    return (
      <div className="space-y-6">
        {sections.map((sec, idx) => {
          const lines = sec.trim().split('\n');
          const title = lines[0].trim();
          const body = lines.slice(1).join('\n').trim();

          let Icon = Activity;
          if (title.includes("指令") || title.includes("操作")) Icon = Target;
          if (title.includes("诊断") || title.includes("持仓")) Icon = ShieldCheck;
          if (title.includes("局势") || title.includes("大盘")) Icon = TrendingUp;

          return (
            <div key={idx} className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm hover:shadow-md transition-shadow">
              <div className="px-6 py-4 bg-slate-50 border-b border-slate-200 flex items-center gap-2">
                <Icon className="w-5 h-5 text-indigo-500" />
                <h3 className="font-black text-slate-800 text-lg">
                  {title}
                </h3>
              </div>
              <div className="p-6">
                <div className="prose prose-slate max-w-none text-sm text-slate-600 leading-relaxed whitespace-pre-wrap">
                  {body}
                </div>
              </div>
            </div>
          );
        })}
      </div>
    );
  };

  const saveToJournal = () => {
    if (!analysisResult) return;
    const entry: JournalEntry = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      snapshot: { ...snapshot },
      analysis: analysisResult
    };
    setJournal([entry, ...journal]);
    alert("复盘日志已保存！");
  };

  return (
    <div className="space-y-6 animate-fade-in max-w-7xl mx-auto pb-20">
      {/* 顶部 Banner */}
      <div className="bg-slate-900 rounded-[2.5rem] p-8 md:p-12 text-white shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-8 opacity-10">
          <TrendingUp className="w-40 h-40" />
        </div>
        <div className="relative z-10">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
              <h2 className="text-3xl font-black mb-2 flex items-center gap-3">
                <LayoutGrid className="w-8 h-8 text-indigo-400" />
                智能复盘审计系统
              </h2>
              <p className="text-slate-400 font-medium">
                上传券商截图（东吴、同花顺等），由 AI 深度扫描主力成本并生成实战指令。
              </p>
            </div>
            <div className="flex gap-3">
              <button 
                onClick={() => setIsHistoryOpen(!isHistoryOpen)}
                className="flex items-center gap-2 px-5 py-3 bg-white/10 hover:bg-white/20 rounded-2xl font-bold transition-all border border-white/10"
              >
                <History className="w-5 h-5" /> 历史记录
              </button>
              <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />
              <button 
                onClick={() => fileInputRef.current?.click()}
                disabled={parsing}
                className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-black shadow-xl transition-all ${parsing ? 'bg-slate-700' : 'bg-indigo-600 hover:bg-indigo-700'}`}
              >
                {parsing ? <Loader2 className="w-5 h-5 animate-spin" /> : <Camera className="w-5 h-5" />}
                {parsing ? '正在提取持仓...' : '上传持仓截图'}
              </button>
            </div>
          </div>
        </div>
      </div>

      {isHistoryOpen && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 animate-slide-down">
          {journal.length === 0 ? (
            <div className="col-span-3 text-center py-8 bg-white rounded-2xl border border-dashed text-slate-400 font-bold">暂无历史记录</div>
          ) : journal.slice(0, 3).map((j) => (
            <div key={j.id} className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm flex items-center justify-between hover:border-indigo-400 transition-all cursor-pointer" onClick={() => { setSnapshot(j.snapshot); setAnalysisResult(j.analysis); setIsHistoryOpen(false); }}>
              <div>
                <div className="text-xs font-black text-slate-400 uppercase tracking-widest">{new Date(j.timestamp).toLocaleDateString()}</div>
                <div className="text-sm font-bold text-slate-800">资产: ¥{j.snapshot.totalAssets.toLocaleString()}</div>
              </div>
              <div className="p-2 text-indigo-600">
                <ChevronRight className="w-5 h-5" />
              </div>
            </div>
          ))}
        </div>
      )}

      {error && (
        <div className="p-4 bg-rose-50 border border-rose-100 rounded-2xl text-rose-700 flex items-center gap-3 font-bold shadow-sm animate-fade-in">
          <AlertTriangle className="w-5 h-5" /> {error}
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* 左栏：持仓数据 */}
        <div className="lg:col-span-4 space-y-6">
          <div className="bg-white rounded-[2rem] border border-slate-200 shadow-sm p-8">
            <h3 className="text-lg font-black text-slate-800 mb-6 flex items-center gap-2">
              <CheckCircle2 className="w-5 h-5 text-emerald-500" />
              当前持仓数据
            </h3>

            <div className="grid grid-cols-2 gap-4 mb-8">
              <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 text-center">
                <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">总资产</div>
                <div className="text-lg font-black text-slate-800 tracking-tight">¥{snapshot.totalAssets.toLocaleString()}</div>
              </div>
              <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 text-center">
                <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">仓位比例</div>
                <div className="text-lg font-black text-indigo-600">{snapshot.positionRatio || '--'}%</div>
              </div>
            </div>

            <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
              {snapshot.holdings.map((h, i) => (
                <div key={i} className="p-4 bg-slate-50 rounded-2xl border border-slate-100 flex justify-between items-center group hover:bg-white hover:border-indigo-400 transition-all">
                  <div>
                    <div className="font-black text-slate-800 truncate max-w-[120px]">{h.name}</div>
                    <div className="text-[10px] font-mono text-slate-400">{h.code}</div>
                  </div>
                  <div className="text-right">
                    <div className={`text-sm font-black ${h.profit >= 0 ? 'text-rose-500' : 'text-emerald-500'}`}>
                      {h.profit >= 0 ? '+' : ''}{h.profitRate}
                    </div>
                    <div className="text-[10px] font-bold text-slate-400">市值: {h.marketValue ? h.marketValue.toLocaleString() : '--'}</div>
                  </div>
                </div>
              ))}
              {snapshot.holdings.length === 0 && (
                <div className="py-20 text-center text-slate-300 font-bold border-2 border-dashed rounded-[2rem] flex flex-col items-center gap-2">
                  <Info className="w-8 h-8 opacity-20" />
                  <p>待上传识别结果</p>
                </div>
              )}
            </div>

            <button 
              onClick={handleAnalyze}
              disabled={loading || snapshot.holdings.length === 0}
              className="w-full mt-8 h-14 bg-slate-900 text-white rounded-2xl font-black shadow-xl flex items-center justify-center gap-3 disabled:opacity-50 transition-transform active:scale-95"
            >
              {loading ? <Loader2 className="w-6 h-6 animate-spin" /> : <TrendingUp className="w-6 h-6" />}
              {loading ? 'AI 复盘中...' : '开始 A 股全维度审计'}
            </button>
          </div>
        </div>

        {/* 右栏：报告与计划 */}
        <div className="lg:col-span-8 space-y-6">
          {(loading || analysisResult || tradingPlans.length > 0) && (
            <div className="bg-white rounded-[2rem] border border-slate-200 shadow-sm overflow-hidden min-h-[600px]">
              <div className="px-8 py-5 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                <div className="flex gap-6">
                  <button 
                    onClick={() => setActiveTab('report')}
                    className={`pb-4 text-sm font-black transition-all border-b-4 ${activeTab === 'report' ? 'text-indigo-600 border-indigo-600' : 'text-slate-400 border-transparent hover:text-slate-600'}`}
                  >
                    AI 审计报告
                  </button>
                  <button 
                    onClick={() => setActiveTab('plans')}
                    className={`pb-4 text-sm font-black transition-all border-b-4 ${activeTab === 'plans' ? 'text-emerald-600 border-emerald-600' : 'text-slate-400 border-transparent hover:text-slate-600'}`}
                  >
                    明日交易计划
                  </button>
                </div>
                {activeTab === 'report' && analysisResult && !loading && (
                  <div className="flex gap-2">
                    <button onClick={saveToJournal} className="p-2.5 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-100 transition-all" title="保存日志"><Save className="w-5 h-5" /></button>
                    <button onClick={generateTradingPlan} className="flex items-center gap-2 px-4 py-2.5 bg-emerald-600 text-white rounded-xl font-bold text-sm shadow-lg shadow-emerald-100 hover:bg-emerald-700 transition-all">
                      <ListTodo className="w-4 h-4" /> 生成计划表
                    </button>
                  </div>
                )}
              </div>

              <div className="p-8">
                {loading ? (
                   <div className="py-40 flex flex-col items-center justify-center text-slate-400 animate-pulse">
                      <Loader2 className="w-16 h-16 animate-spin mb-6 text-indigo-600" />
                      <p className="text-xl font-black text-slate-800 mb-2">{loadingPhase}</p>
                      <p className="text-sm font-medium">AI 正在深度拆解您的每一笔头寸...</p>
                   </div>
                ) : activeTab === 'report' && analysisResult ? (
                  renderReportContent(analysisResult.content)
                ) : activeTab === 'plans' ? (
                  <div className="space-y-6">
                    {tradingPlans.length === 0 ? (
                      <div className="py-40 text-center flex flex-col items-center gap-4">
                         <XCircle className="w-16 h-16 text-slate-100" />
                         <p className="text-slate-300 font-black italic">点击“生成计划表”开启职业化操盘</p>
                      </div>
                    ) : (
                      tradingPlans.map(plan => (
                        <div key={plan.id} className="bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm">
                          <div className="px-6 py-4 bg-slate-900 text-white flex justify-between items-center">
                            <div className="flex items-center gap-3">
                              <Calendar className="w-5 h-5 text-indigo-400" />
                              <span className="font-black">计划日期: {plan.target_date}</span>
                            </div>
                            <span className="text-[10px] font-black uppercase tracking-widest text-indigo-300">Live Strategy</span>
                          </div>
                          <div className="p-6 space-y-4">
                            <div className="bg-indigo-50 p-4 rounded-2xl text-indigo-900 text-sm font-bold italic border border-indigo-100">
                              “{plan.strategy_summary}”
                            </div>
                            <div className="grid grid-cols-1 gap-3">
                              {plan.items.map(item => (
                                <div key={item.id} className="flex items-center gap-4 p-4 bg-slate-50 rounded-2xl border border-slate-100 group transition-all hover:bg-white hover:border-indigo-200">
                                  <div className={`w-3 h-3 rounded-full shrink-0 ${item.action === 'buy' ? 'bg-rose-500' : item.action === 'sell' ? 'bg-emerald-500' : 'bg-slate-300'}`} />
                                  <div className="flex-1">
                                    <div className="flex items-center gap-2">
                                      <span className="font-black text-slate-800">{item.symbol}</span>
                                      <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase ${item.action === 'buy' ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>{item.action}</span>
                                    </div>
                                    <div className="text-xs text-slate-500 font-medium">{item.reason}</div>
                                  </div>
                                  <div className="text-right">
                                    <div className="text-sm font-black text-slate-800">{item.price_target || '--'}</div>
                                    <div className="text-[9px] font-bold text-slate-400 uppercase">Target Price</div>
                                  </div>
                                </div>
                              ))}
                            </div>
                          </div>
                        </div>
                      ))
                    )}
                  </div>
                ) : (
                  <div className="py-40 flex flex-col items-center justify-center text-slate-200">
                    <ArrowRightCircle className="w-16 h-16 opacity-10 mb-6" />
                    <p className="text-2xl font-black">等待深度审计指令</p>
                  </div>
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { ModelProvider, AnalysisResult, UserSettings, MarketType, HoldingsSnapshot, HoldingItemDetailed, JournalEntry, DailyTradingPlan, PlanItem } from '../types';
import { analyzeWithLLM } from '../services/llmAdapter';
import { parseBrokerageScreenshot, extractTradingPlan } from '../services/geminiService';
import { Upload, Loader2, Save, History, Trash2, Camera, Edit2, Check, X, FileJson, TrendingUp, AlertTriangle, ListTodo, Calendar, Download, FileText, ChevronRight, LayoutGrid, CheckCircle2, XCircle, MoreHorizontal, Info, Target, ShieldCheck, Activity, ArrowRightCircle, DatabaseBackup, FileOutput, FileInput } from 'lucide-react';
import { MARKET_OPTIONS } from '../constants';

interface HoldingsReviewProps {
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: UserSettings;
  onOpenSettings?: () => void;
}

export const HoldingsReview: React.FC<HoldingsReviewProps> = ({
  currentModel,
  currentMarket,
  settings,
  onOpenSettings
}) => {
  const [snapshot, setSnapshot] = useState<HoldingsSnapshot>({
    totalAssets: 0,
    positionRatio: 0, 
    date: new Date().toISOString().split('T')[0],
    holdings: []
  });

  const [journal, setJournal] = useState<JournalEntry[]>(() => {
    const saved = localStorage.getItem('qm_journal');
    return saved ? JSON.parse(saved) : [];
  });

  const [tradingPlans, setTradingPlans] = useState<DailyTradingPlan[]>(() => {
    const saved = localStorage.getItem('qm_trading_plans');
    return saved ? JSON.parse(saved) : [];
  });

  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [parsing, setParsing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'report' | 'plans'>('report');
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [loadingPhase, setLoadingPhase] = useState("");

  const fileInputRef = useRef<HTMLInputElement>(null);
  const importFileRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    localStorage.setItem('qm_journal', JSON.stringify(journal));
  }, [journal]);

  useEffect(() => {
    localStorage.setItem('qm_trading_plans', JSON.stringify(tradingPlans));
  }, [tradingPlans]);

  // --- 导入导出核心逻辑 ---
  const handleExportData = () => {
    try {
      const dataToExport = {
        version: "1.0",
        exportDate: new Date().toISOString(),
        journal,
        tradingPlans
      };
      const blob = new Blob([JSON.stringify(dataToExport, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `QuantMind_Backup_${new Date().toISOString().split('T')[0]}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    } catch (err) {
      setError("导出失败，请重试。");
    }
  };

  const handleImportData = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const content = event.target?.result as string;
        const imported = JSON.parse(content);

        if (!imported.journal || !imported.tradingPlans) {
          throw new Error("文件格式不正确，缺少核心数据。");
        }

        if (window.confirm("导入将合并现有数据，是否继续？")) {
          // 合并逻辑：去重合并
          const mergedJournal = [...imported.journal, ...journal].filter((v, i, a) => a.findIndex(t => t.id === v.id) === i);
          const mergedPlans = [...imported.tradingPlans, ...tradingPlans].filter((v, i, a) => a.findIndex(t => t.id === v.id) === i);

          setJournal(mergedJournal);
          setTradingPlans(mergedPlans);
          alert("数据导入并合并成功！");
        }
      } catch (err) {
        setError("导入失败：请选择有效的 QuantMind 备份文件。");
      }
    };
    reader.readAsText(file);
    // 重置 input 以便下次选择同一文件
    if (importFileRef.current) importFileRef.current.value = "";
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setParsing(true);
    setError(null);

    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = (reader.result as string).split(',')[1];
        try {
          const parsedData = await parseBrokerageScreenshot(base64String, settings.geminiKey);
          setSnapshot({
            ...parsedData,
            totalAssets: parsedData.totalAssets || 0,
            date: new Date().toISOString().split('T')[0]
          });
        } catch (err: any) {
          setError("识别失败：无法解析该截图内容。");
        } finally {
          setParsing(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setParsing(false);
      setError("文件读取失败");
    }
  };

  const handleAnalyze = async () => {
    if (snapshot.holdings.length === 0) {
      setError("请先上传持仓截图或手动录入标的");
      return;
    }

    setLoading(true);
    setAnalysisResult(null);
    setError(null);
    setLoadingPhase("正在联网检索最新行情与 L2 资金流向...");

    const lastEntry = journal[0]; 
    const contextHistory = lastEntry 
      ? `[历史基准] 上次复盘总资产 ¥${lastEntry.snapshot.totalAssets}。`
      : "首次复盘，无历史基准。";

    const prompt = `作为顶级 A 股量化顾问，请对我的持仓进行【连续性深度审计】。${contextHistory} \n\n === 当前持仓详情 (总资产: ¥${snapshot.totalAssets}) === \n ${snapshot.holdings.map(h => `- ${h.name} (${h.code}): 成本 ${h.costPrice}, 现价 ${h.currentPrice}, 盈亏 ${h.profitRate}`).join('\n')} \n\n 【要求】: \n 1. 包含具体的【支撑位】与【止损建议】。\n 2. 结合今日大盘解释盈亏波动原因。\n 3. 必须包含一个【实战交易指令】章节。 \n 请使用 Markdown 格式输出。`;

    try {
      setTimeout(() => setLoadingPhase("正在进行个股支撑/压力位计算..."), 2000);
      const result = await analyzeWithLLM(currentModel, prompt, true, settings, false, 'day', undefined, currentMarket);
      setAnalysisResult(result);
      setActiveTab('report');
    } catch (err: any) {
      setError(err.message || "分析请求失败");
    } finally {
      setLoading(false);
      setLoadingPhase("");
    }
  };

  const generateTradingPlan = async () => {
    if (!analysisResult) return;
    setLoading(true);
    setLoadingPhase("正在生成计划表...");
    try {
      const plan = await extractTradingPlan(analysisResult.content, settings.geminiKey);
      const newPlan: DailyTradingPlan = {
        id: crypto.randomUUID(),
        target_date: new Date(Date.now() + 86400000).toISOString().split('T')[0],
        created_at: Date.now(),
        items: plan.items,
        strategy_summary: plan.summary
      };
      setTradingPlans([newPlan, ...tradingPlans]);
      setActiveTab('plans');
    } catch (err) {
      setError("生成交易计划失败");
    } finally {
      setLoading(false);
      setLoadingPhase("");
    }
  };

  const renderReportContent = (content: string) => {
    if (!content) return <div className="p-8 text-slate-400">无内容显示</div>;
    const sections = content.split(/^(?:##|###)\s+/gm).filter(Boolean);
    if (sections.length <= 1) {
      return <div className="p-8 bg-white rounded-2xl border border-slate-200"><div className="prose prose-slate max-w-none text-slate-600 whitespace-pre-wrap">{content}</div></div>;
    }

    return (
      <div className="space-y-6">
        {sections.map((sec, idx) => {
          const lines = sec.trim().split('\n');
          const title = lines[0].trim();
          const body = lines.slice(1).join('\n').trim();
          let Icon = Activity;
          if (title.includes("指令") || title.includes("操作")) Icon = Target;
          if (title.includes("诊断") || title.includes("持仓")) Icon = ShieldCheck;
          if (title.includes("局势") || title.includes("大盘")) Icon = TrendingUp;

          return (
            <div key={idx} className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm hover:shadow-md transition-shadow">
              <div className="px-6 py-4 bg-slate-50 border-b border-slate-200 flex items-center gap-2">
                <Icon className="w-5 h-5 text-indigo-500" />
                <h3 className="font-black text-slate-800 text-lg">{title}</h3>
              </div>
              <div className="p-6">
                <div className="prose prose-slate max-w-none text-sm text-slate-600 leading-relaxed whitespace-pre-wrap">{body}</div>
              </div>
            </div>
          );
        })}
      </div>
    );
  };

  const saveToJournal = () => {
    if (!analysisResult) return;
    const entry: JournalEntry = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      snapshot: { ...snapshot },
      analysis: analysisResult
    };
    setJournal([entry, ...journal]);
    alert("复盘日志已保存！");
  };

  return (
    <div className="space-y-6 animate-fade-in max-w-7xl mx-auto pb-20">
      {/* 顶部 Banner */}
      <div className="bg-slate-900 rounded-[2.5rem] p-8 md:p-12 text-white shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-8 opacity-10">
          <TrendingUp className="w-40 h-40" />
        </div>
        <div className="relative z-10">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
              <h2 className="text-3xl font-black mb-2 flex items-center gap-3">
                <LayoutGrid className="w-8 h-8 text-indigo-400" />
                智能复盘审计系统
              </h2>
              <p className="text-slate-400 font-medium">
                上传券商截图（东吴、同花顺等），由 AI 深度扫描主力成本并生成实战指令。
              </p>
            </div>
            <div className="flex flex-wrap gap-2">
              <button 
                onClick={() => setIsHistoryOpen(!isHistoryOpen)}
                className="flex items-center gap-2 px-4 py-2.5 bg-white/10 hover:bg-white/20 rounded-xl font-bold transition-all border border-white/10 text-sm"
              >
                <History className="w-4 h-4" /> 历史记录
              </button>

              <div className="h-10 w-[1px] bg-white/10 mx-1 self-center" />

              <button 
                onClick={handleExportData}
                className="p-2.5 bg-white/10 hover:bg-indigo-500/30 rounded-xl text-white transition-all border border-white/10"
                title="导出备份"
              >
                <FileOutput className="w-4 h-4" />
              </button>
              <input type="file" ref={importFileRef} className="hidden" accept=".json" onChange={handleImportData} />
              <button 
                onClick={() => importFileRef.current?.click()}
                className="p-2.5 bg-white/10 hover:bg-emerald-500/30 rounded-xl text-white transition-all border border-white/10"
                title="导入还原"
              >
                <FileInput className="w-4 h-4" />
              </button>

              <div className="h-10 w-[1px] bg-white/10 mx-1 self-center" />

              <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />
              <button 
                onClick={() => fileInputRef.current?.click()}
                disabled={parsing}
                className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-black shadow-xl transition-all ${parsing ? 'bg-slate-700' : 'bg-indigo-600 hover:bg-indigo-700'}`}
              >
                {parsing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Camera className="w-4 h-4" />}
                {parsing ? '提取中...' : '上传截图'}
              </button>
            </div>
          </div>
        </div>
      </div>

      {isHistoryOpen && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 animate-slide-down">
          {journal.length === 0 ? (
            <div className="col-span-3 text-center py-8 bg-white rounded-2xl border border-dashed text-slate-400 font-bold">暂无复盘记录</div>
          ) : journal.slice(0, 3).map((j) => (
            <div key={j.id} className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm flex items-center justify-between hover:border-indigo-400 transition-all cursor-pointer" onClick={() => { setSnapshot(j.snapshot); setAnalysisResult(j.analysis); setIsHistoryOpen(false); }}>
              <div>
                <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{new Date(j.timestamp).toLocaleDateString()}</div>
                <div className="text-sm font-bold text-slate-800">资产: ¥{j.snapshot.totalAssets.toLocaleString()}</div>
              </div>
              <ChevronRight className="w-5 h-5 text-indigo-600" />
            </div>
          ))}
        </div>
      )}

      {error && (
        <div className="p-4 bg-rose-50 border border-rose-100 rounded-2xl text-rose-700 flex items-center gap-3 font-bold shadow-sm animate-fade-in">
          <AlertTriangle className="w-5 h-5" /> {error}
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-4 space-y-6">
          <div className="bg-white rounded-[2rem] border border-slate-200 shadow-sm p-8">
            <h3 className="text-lg font-black text-slate-800 mb-6 flex items-center gap-2">
              <CheckCircle2 className="w-5 h-5 text-emerald-500" />
              当前持仓快照
            </h3>
            <div className="grid grid-cols-2 gap-4 mb-8">
              <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 text-center">
                <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">总资产</div>
                <div className="text-lg font-black text-slate-800 tracking-tight">¥{snapshot.totalAssets.toLocaleString()}</div>
              </div>
              <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 text-center">
                <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">仓位比例</div>
                <div className="text-lg font-black text-indigo-600">{snapshot.positionRatio || '--'}%</div>
              </div>
            </div>

            <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
              {snapshot.holdings.map((h, i) => (
                <div key={i} className="p-4 bg-slate-50 rounded-2xl border border-slate-100 flex justify-between items-center group hover:bg-white hover:border-indigo-400 transition-all">
                  <div>
                    <div className="font-black text-slate-800 truncate max-w-[120px]">{h.name}</div>
                    <div className="text-[10px] font-mono text-slate-400">{h.code}</div>
                  </div>
                  <div className="text-right">
                    <div className={`text-sm font-black ${h.profit >= 0 ? 'text-rose-500' : 'text-emerald-500'}`}>
                      {h.profitRate}
                    </div>
                    <div className="text-[10px] font-bold text-slate-400">市值: {h.marketValue ? h.marketValue.toLocaleString() : '--'}</div>
                  </div>
                </div>
              ))}
              {snapshot.holdings.length === 0 && (
                <div className="py-20 text-center text-slate-300 font-bold border-2 border-dashed rounded-[2rem] flex flex-col items-center gap-2">
                  <Info className="w-8 h-8 opacity-20" />
                  <p>待上传识别结果</p>
                </div>
              )}
            </div>

            <button 
              onClick={handleAnalyze}
              disabled={loading || snapshot.holdings.length === 0}
              className="w-full mt-8 h-14 bg-slate-900 text-white rounded-2xl font-black shadow-xl flex items-center justify-center gap-3 disabled:opacity-50 transition-transform active:scale-95"
            >
              {loading ? <Loader2 className="w-6 h-6 animate-spin" /> : <TrendingUp className="w-6 h-6" />}
              {loading ? 'AI 审计中...' : '开始 A 股全维度审计'}
            </button>
          </div>
        </div>

        <div className="lg:col-span-8 space-y-6">
          {(loading || analysisResult || tradingPlans.length > 0) && (
            <div className="bg-white rounded-[2rem] border border-slate-200 shadow-sm overflow-hidden min-h-[600px]">
              <div className="px-8 py-5 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                <div className="flex gap-6">
                  <button onClick={() => setActiveTab('report')} className={`pb-4 text-sm font-black transition-all border-b-4 ${activeTab === 'report' ? 'text-indigo-600 border-indigo-600' : 'text-slate-400 border-transparent hover:text-slate-600'}`}>AI 审计报告</button>
                  <button onClick={() => setActiveTab('plans')} className={`pb-4 text-sm font-black transition-all border-b-4 ${activeTab === 'plans' ? 'text-emerald-600 border-emerald-600' : 'text-slate-400 border-transparent hover:text-slate-600'}`}>明日交易计划</button>
                </div>
                {activeTab === 'report' && analysisResult && !loading && (
                  <div className="flex gap-2">
                    <button onClick={saveToJournal} className="p-2.5 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-100 transition-all"><Save className="w-5 h-5" /></button>
                    <button onClick={generateTradingPlan} className="flex items-center gap-2 px-4 py-2.5 bg-emerald-600 text-white rounded-xl font-bold text-sm shadow-lg shadow-emerald-100 hover:bg-emerald-700 transition-all"><ListTodo className="w-4 h-4" /> 生成计划表</button>
                  </div>
                )}
              </div>

              <div className="p-8">
                {loading ? (
                   <div className="py-40 flex flex-col items-center justify-center text-slate-400">
                      <Loader2 className="w-16 h-16 animate-spin mb-6 text-indigo-600" />
                      <p className="text-xl font-black text-slate-800 mb-2">{loadingPhase}</p>
                   </div>
                ) : activeTab === 'report' && analysisResult ? (
                  renderReportContent(analysisResult.content)
                ) : activeTab === 'plans' ? (
                  <div className="space-y-6">
                    {tradingPlans.length === 0 ? (
                      <div className="py-40 text-center flex flex-col items-center gap-4"><XCircle className="w-16 h-16 text-slate-100" /><p className="text-slate-300 font-black italic">点击“生成计划表”开启职业化操盘</p></div>
                    ) : (
                      tradingPlans.map(plan => (
                        <div key={plan.id} className="bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm">
                          <div className="px-6 py-4 bg-slate-900 text-white flex justify-between items-center">
                            <div className="flex items-center gap-3"><Calendar className="w-5 h-5 text-indigo-400" /><span className="font-black">计划日期: {plan.target_date}</span></div>
                          </div>
                          <div className="p-6 space-y-4">
                            <div className="bg-indigo-50 p-4 rounded-2xl text-indigo-900 text-sm font-bold italic border border-indigo-100">“{plan.strategy_summary}”</div>
                            <div className="grid grid-cols-1 gap-3">
                              {plan.items.map(item => (
                                <div key={item.id} className="flex items-center gap-4 p-4 bg-slate-50 rounded-2xl border border-slate-100 hover:bg-white hover:border-indigo-200 transition-all">
                                  <div className={`w-3 h-3 rounded-full shrink-0 ${item.action === 'buy' ? 'bg-rose-500' : item.action === 'sell' ? 'bg-emerald-500' : 'bg-slate-300'}`} />
                                  <div className="flex-1">
                                    <div className="flex items-center gap-2"><span className="font-black text-slate-800">{item.symbol}</span><span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase ${item.action === 'buy' ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>{item.action}</span></div>
                                    <div className="text-xs text-slate-500 font-medium">{item.reason}</div>
                                  </div>
                                  <div className="text-right"><div className="text-sm font-black text-slate-800">{item.price_target || '--'}</div><div className="text-[9px] font-bold text-slate-400 uppercase">Target</div></div>
                                </div>
                              ))}
                            </div>
                          </div>
                        </div>
                      ))
                    )}
                  </div>
                ) : (
                  <div className="py-40 flex flex-col items-center justify-center text-slate-200"><ArrowRightCircle className="w-16 h-16 opacity-10 mb-6" /><p className="text-2xl font-black">等待深度审计指令</p></div>
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { ModelProvider, AnalysisResult, UserSettings, MarketType, HoldingsSnapshot, HoldingItemDetailed, JournalEntry, DailyTradingPlan, PlanItem } from '../types';
import { analyzeWithLLM } from '../services/llmAdapter';
import { parseBrokerageScreenshot, extractTradingPlan } from '../services/geminiService';
import { Upload, Loader2, Save, History, Trash2, Camera, Edit2, Check, X, FileJson, TrendingUp, AlertTriangle, ListTodo, Calendar, Download, FileText, ChevronRight, LayoutGrid, CheckCircle2, XCircle, MoreHorizontal, Info, Target, ShieldCheck, Activity, ArrowRightCircle, DatabaseBackup, FileOutput, FileInput, CheckCircle } from 'lucide-react';
import { MARKET_OPTIONS } from '../constants';

const STORAGE_KEYS = {
  JOURNAL: 'qm_journal_v2',
  PLANS: 'qm_trading_plans_v2'
};

interface HoldingsReviewProps {
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: UserSettings;
  onOpenSettings?: () => void;
}

export const HoldingsReview: React.FC<HoldingsReviewProps> = ({
  currentModel,
  currentMarket,
  settings,
  onOpenSettings
}) => {
  const [snapshot, setSnapshot] = useState<HoldingsSnapshot>({
    totalAssets: 0,
    positionRatio: 0, 
    date: new Date().toISOString().split('T')[0],
    holdings: []
  });

  const [journal, setJournal] = useState<JournalEntry[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEYS.JOURNAL);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load journal", e);
      return [];
    }
  });

  const [tradingPlans, setTradingPlans] = useState<DailyTradingPlan[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEYS.PLANS);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [parsing, setParsing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'report' | 'plans'>('report');
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [loadingPhase, setLoadingPhase] = useState("");
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved'>('idle');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const importFileRef = useRef<HTMLInputElement>(null);

  // 监听 journal 变化进行持久化，增加错误处理（防止 QuotaExceededError）
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEYS.JOURNAL, JSON.stringify(journal));
    } catch (e) {
      console.error("LocalStorage save failed, quota might be full.", e);
      if (e instanceof DOMException && e.name === 'QuotaExceededError') {
        setError("存储空间已满，请清理历史复盘记录。");
      }
    }
  }, [journal]);

  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEYS.PLANS, JSON.stringify(tradingPlans));
    } catch (e) {}
  }, [tradingPlans]);

  // 安全 ID 生成器
  const generateId = () => {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
      return crypto.randomUUID();
    }
    return `id-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
  };

  const handleExportData = () => {
    try {
      const dataToExport = {
        version: "1.1",
        exportDate: new Date().toISOString(),
        journal,
        tradingPlans
      };
      const blob = new Blob([JSON.stringify(dataToExport, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `QuantMind_Backup_${new Date().toISOString().split('T')[0]}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    } catch (err) {
      setError("导出失败");
    }
  };

  const handleImportData = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const imported = JSON.parse(event.target?.result as string);
        if (window.confirm("确定要合并导入的历史复盘数据吗？")) {
          setJournal(prev => {
            const combined = [...(imported.journal || []), ...prev];
            return combined.filter((v, i, a) => a.findIndex(t => t.id === v.id) === i);
          });
          setTradingPlans(prev => {
            const combined = [...(imported.tradingPlans || []), ...prev];
            return combined.filter((v, i, a) => a.findIndex(t => t.id === v.id) === i);
          });
          alert("导入成功！");
        }
      } catch (err) {
        setError("文件解析失败");
      }
    };
    reader.readAsText(file);
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setParsing(true);
    setError(null);
    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = (reader.result as string).split(',')[1];
        try {
          const parsedData = await parseBrokerageScreenshot(base64String, settings.geminiKey);
          setSnapshot({
            ...parsedData,
            totalAssets: parsedData.totalAssets || 0,
            date: new Date().toISOString().split('T')[0]
          });
        } catch (err: any) {
          setError("识别失败");
        } finally {
          setParsing(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setParsing(false);
    }
  };

  const handleAnalyze = async () => {
    if (snapshot.holdings.length === 0) {
      setError("请先上传持仓截图");
      return;
    }
    setLoading(true);
    setAnalysisResult(null);
    setError(null);
    setSaveStatus('idle');
    setLoadingPhase("正在联网检索 L2 资金与最新公告...");

    const lastEntry = journal[0]; 
    const contextHistory = lastEntry 
      ? `[上次总资产: ¥${lastEntry.snapshot.totalAssets}]`
      : "";

    const prompt = `作为首席量化顾问，请分析当前持仓。${contextHistory} \n\n === 资产: ¥${snapshot.totalAssets} === \n ${snapshot.holdings.map(h => `- ${h.name}: ${h.profitRate}`).join('\n')} \n\n 要求输出包含【支撑压力】与【实战指令】。请用 Markdown 格式。`;

    try {
      const result = await analyzeWithLLM(currentModel, prompt, true, settings, false, 'day', undefined, currentMarket);
      setAnalysisResult(result);
      setActiveTab('report');
    } catch (err: any) {
      setError(err.message || "分析请求失败");
    } finally {
      setLoading(false);
      setLoadingPhase("");
    }
  };

  const saveToJournal = () => {
    if (!analysisResult || saveStatus === 'saved') return;

    setSaveStatus('saving');

    // 构建新条目
    const entry: JournalEntry = {
      id: generateId(),
      timestamp: Date.now(),
      snapshot: { ...snapshot },
      analysis: analysisResult
    };

    // 使用函数式更新确保最新状态
    setJournal(prev => [entry, ...prev]);

    // UI反馈
    setTimeout(() => {
      setSaveStatus('saved');
      setIsHistoryOpen(true); // 自动展开历史记录让用户看到
      setTimeout(() => setSaveStatus('idle'), 3000);
    }, 500);
  };

  const clearJournal = () => {
    if (window.confirm("确定要清空所有历史复盘日志吗？此操作不可撤销。")) {
      setJournal([]);
      localStorage.removeItem(STORAGE_KEYS.JOURNAL);
    }
  };

  const renderReportContent = (content: string) => {
    if (!content) return <div className="p-8 text-slate-400">无内容显示</div>;
    const sections = content.split(/^(?:##|###)\s+/gm).filter(Boolean);
    if (sections.length <= 1) {
      return <div className="p-8 bg-white rounded-2xl border border-slate-200"><div className="prose prose-slate max-w-none text-slate-600 whitespace-pre-wrap">{content}</div></div>;
    }
    return (
      <div className="space-y-6">
        {sections.map((sec, idx) => {
          const lines = sec.trim().split('\n');
          const title = lines[0].trim();
          const body = lines.slice(1).join('\n').trim();
          let Icon = Activity;
          if (title.includes("指令") || title.includes("操作")) Icon = Target;
          if (title.includes("诊断") || title.includes("持仓")) Icon = ShieldCheck;
          if (title.includes("局势") || title.includes("大盘")) Icon = TrendingUp;
          return (
            <div key={idx} className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm hover:shadow-md">
              <div className="px-6 py-4 bg-slate-50 border-b flex items-center gap-2">
                <Icon className="w-5 h-5 text-indigo-500" />
                <h3 className="font-black text-slate-800 text-lg">{title}</h3>
              </div>
              <div className="p-6"><div className="prose prose-slate max-w-none text-sm text-slate-600 whitespace-pre-wrap">{body}</div></div>
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="space-y-6 animate-fade-in max-w-7xl mx-auto pb-20">
      <div className="bg-slate-900 rounded-[2.5rem] p-8 md:p-12 text-white shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-8 opacity-10"><TrendingUp className="w-40 h-40" /></div>
        <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-6">
          <div>
            <h2 className="text-3xl font-black mb-2 flex items-center gap-3"><LayoutGrid className="w-8 h-8 text-indigo-400" />智能复盘审计系统</h2>
            <p className="text-slate-400 font-medium text-sm">解析截图，由 AI 深度扫描主力成本并生成实战指令。</p>
          </div>
          <div className="flex flex-wrap gap-2">
            <button onClick={() => setIsHistoryOpen(!isHistoryOpen)} className="flex items-center gap-2 px-4 py-2.5 bg-white/10 hover:bg-white/20 rounded-xl font-bold transition-all border border-white/10 text-sm">
              <History className="w-4 h-4" /> {isHistoryOpen ? '收起历史' : '历史记录'}
            </button>
            <button onClick={handleExportData} className="p-2.5 bg-white/10 hover:bg-indigo-500/30 rounded-xl text-white transition-all border border-white/10"><FileOutput className="w-4 h-4" /></button>
            <input type="file" ref={importFileRef} className="hidden" accept=".json" onChange={handleImportData} />
            <button onClick={() => importFileRef.current?.click()} className="p-2.5 bg-white/10 hover:bg-emerald-500/30 rounded-xl text-white transition-all border border-white/10"><FileInput className="w-4 h-4" /></button>
            <div className="h-10 w-[1px] bg-white/10 mx-1 self-center" />
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />
            <button onClick={() => fileInputRef.current?.click()} disabled={parsing} className="flex items-center gap-2 px-6 py-2.5 rounded-xl font-black bg-indigo-600 hover:bg-indigo-700 transition-all shadow-xl disabled:opacity-50">
              {parsing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Camera className="w-4 h-4" />}
              {parsing ? '提取中...' : '上传截图'}
            </button>
          </div>
        </div>
      </div>

      {isHistoryOpen && (
        <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm animate-slide-down space-y-4">
           <div className="flex justify-between items-center px-2">
