  const parts = [{ text: `诊断股票 ${query}。现价优先级: ${price || '由图识别'}。` }, { inlineData: { mimeType: 'image/jpeg', data: img } }];
  const response = await ai.models.generateContent({ model: modelName, contents: { parts }, config: { tools: [{ googleSearch: {} }] } });
  return { content: response.text || "", timestamp: Date.now(), modelUsed: ModelProvider.GEMINI_INTL };
};

export const parseBrokerageScreenshot = async (img: string, apiKey?: string, modelName: string = DEFAULT_MODEL): Promise<HoldingsSnapshot> => {
  const ai = new GoogleGenAI({ apiKey: apiKey || process.env.API_KEY });
  const response = await ai.models.generateContent({ model: modelName, contents: { parts: [{ inlineData: { mimeType: 'image/jpeg', data: img } }, { text: "解析截图，输出 JSON。" }] }, config: { responseMimeType: "application/json" } });
  return robustParse(response.text || "{}");
};

export const fetchSectorLadderAnalysis = async (query: string, market: MarketType, apiKey: string, modelName: string = DEFAULT_MODEL): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });
  const response = await ai.models.generateContent({ model: modelName, contents: `分析 ${market} 板块 "${query}"。`, config: { tools: [{ googleSearch: {} }], responseMimeType: "application/json" } });
  return { content: response.text || "", timestamp: Date.now(), modelUsed: ModelProvider.GEMINI_INTL, isStructured: true, ladderData: robustParse(response.text || "{}") };
};

