// Fix: Implemented fetchPeriodicReview for long-term historical analysis in HoldingsReview.tsx
export const fetchPeriodicReview = async (journals: JournalEntry[], periodLabel: string, market: MarketType, apiKey?: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: apiKey || process.env.API_KEY });
  const historyText = journals.map(j => `时间: ${new Date(j.timestamp).toLocaleString()}, 资产: ${j.snapshot.totalAssets}, 持仓: ${JSON.stringify(j.snapshot.holdings)}`).join('\n---\n');
  const prompt = `你是一位资深投资顾问。请针对以下【${periodLabel}】的历史交易记录进行深度总结。
  市场环境：${market}
  历史数据：
  ${historyText}

  请分析大盘趋势、账户表现盈亏比、知行合一程度（执行力），并对每只个股给出诊断和改进建议。`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: periodicReviewSchema
    }
  });

  return { 
    content: response.text || "", 
    timestamp: Date.now(), 
    modelUsed: ModelProvider.GEMINI_INTL, 
    isStructured: true, 
    periodicData: robustParse(response.text || "{}"),
    market 
  };
};

// Fix: Implemented extractTradingPlan to convert analysis text into a structured task list in HoldingsReview.tsx
export const extractTradingPlan = async (analysisContent: string, apiKey?: string): Promise<{ items: PlanItem[], summary: string }> => {
  const ai = new GoogleGenAI({ apiKey: apiKey || process.env.API_KEY });
  const prompt = `请从以下复盘报告中提取具体的交易计划（买入/卖出/持股/观察等指令）。
  报告内容：
  ${analysisContent}

  输出必须包含总结和具体的计划项。`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: tradingPlanSchema
    }
  });

  const raw = robustParse(response.text || "{}");
  const items = (raw?.items || []).map((item: any) => ({
    ...item,
    id: Math.random().toString(36).substr(2, 9),
    status: 'pending'
  }));

  return { 
    items, 
    summary: raw?.summary || "暂无策略总结" 
  };
};

