import React, { useState, useEffect, useRef } from 'react';
import { ModelProvider, AnalysisResult, UserSettings, MarketType, HoldingsSnapshot, HoldingItemDetailed, JournalEntry, PeriodicReviewData, DailyTradingPlan, PlanItem } from '../types';
import { analyzeWithLLM } from '../services/llmAdapter';
import { parseBrokerageScreenshot, fetchPeriodicReview, extractTradingPlan } from '../services/geminiService';
import { analyzeImageWithExternal } from '../services/externalLlmService';
import { Upload, Loader2, Save, Download, UploadCloud, History, Trash2, Camera, Edit2, Check, X, FileJson, TrendingUp, AlertTriangle, PieChart as PieChartIcon, Activity, Target, ClipboardList, BarChart3, Crosshair, GitCompare, Clock, LineChart as LineChartIcon, Calendar, Trophy, AlertOctagon, CheckCircle2, XCircle, ArrowRightCircle, ListTodo, MoreHorizontal, Square, CheckSquare, FileText, FileSpreadsheet, FileCode, ChevronLeft, ChevronRight, AlertCircle, Scale, Coins, ShieldAlert, Microscope, MessageSquareQuote, Lightbulb, FileType, BookOpenCheck } from 'lucide-react';
import { MARKET_OPTIONS } from '../constants';
import { PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, ReferenceLine, LineChart, Line } from 'recharts';

interface HoldingsReviewProps {
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: UserSettings;
  onOpenSettings?: () => void;
}

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#6366f1', '#14b8a6'];
const HORIZON_COLORS = {
  'short': '#f59e0b', // Amber
  'medium': '#3b82f6', // Blue
  'long': '#8b5cf6', // Violet
};

const HISTORY_PAGE_SIZE = 5;

export const HoldingsReview: React.FC<HoldingsReviewProps> = ({
  currentModel,
  currentMarket,
  settings,
  onOpenSettings
}) => {
  // --- State ---
  const [snapshot, setSnapshot] = useState<HoldingsSnapshot>({
    totalAssets: 0,
    positionRatio: 0, 
    date: new Date().toISOString().split('T')[0],
    holdings: []
  });

  const [journal, setJournal] = useState<JournalEntry[]>(() => {
    const saved = localStorage.getItem('qm_journal');
    if (!saved) return [];
    try {
      const parsed = JSON.parse(saved);
      return (Array.isArray(parsed) ? parsed : []).map(item => ({
        ...item,
        id: item.id || `legacy-${item.timestamp}-${Math.random().toString(36).substr(2, 9)}`
      }));
    } catch (e) {
      return [];
    }
  });

  const [tradingPlans, setTradingPlans] = useState<DailyTradingPlan[]>(() => {
    const saved = localStorage.getItem('qm_trading_plans');
    return saved ? JSON.parse(saved) : [];
  });

  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [parsing, setParsing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Drawers
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isPlanOpen, setIsPlanOpen] = useState(false);
  const [historyPage, setHistoryPage] = useState(1);

  const [activeTab, setActiveTab] = useState<'report' | 'charts' | 'periodic'>('report');

  // Periodic Review State
  const [periodicResult, setPeriodicResult] = useState<AnalysisResult | null>(null);

  // Editing State
  const [editingIndex, setEditingIndex] = useState<number | null>(null);
  const [editForm, setEditForm] = useState<HoldingItemDetailed | null>(null);

  // Plan Generation State
  const [generatingPlan, setGeneratingPlan] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);

  // --- Effects ---
  useEffect(() => {
    localStorage.setItem('qm_journal', JSON.stringify(journal));
  }, [journal]);

  useEffect(() => {
    localStorage.setItem('qm_trading_plans', JSON.stringify(tradingPlans));
  }, [tradingPlans]);

  // --- Handlers: Screenshot ---
  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const geminiSubModel = settings?.preferredGeminiModel === 'pro' 
      ? 'gemini-3-pro-preview' 
      : 'gemini-3-flash-preview';

    if (currentModel === ModelProvider.HUNYUAN_CN && !settings.hunyuanKey) {
      setError("您当前选择了腾讯混元模型，请配置 Hunyuan API Key 以使用图片识别功能。");
      onOpenSettings?.();
      return;
    }

    if (currentModel === ModelProvider.GEMINI_INTL && !settings.geminiKey) {
      setError("您当前选择了 Gemini 模型，请配置 Gemini API Key 以使用图片识别功能。");
      onOpenSettings?.();
      return;
    }

    setParsing(true);
    setError(null);

    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = (reader.result as string).split(',')[1];
        try {
          let parsedData: HoldingsSnapshot;

          if (currentModel === ModelProvider.HUNYUAN_CN) {
             parsedData = await analyzeImageWithExternal(ModelProvider.HUNYUAN_CN, base64String, settings.hunyuanKey!);
          } else {
             parsedData = await parseBrokerageScreenshot(base64String, settings.geminiKey, geminiSubModel);
          }

          // 核心修复: 确保 holdings 字段存在，防止 map 崩溃
          const safeHoldings = parsedData.holdings || [];
          const holdingsWithHorizon = safeHoldings.map(h => ({ ...h, horizon: 'medium' as const }));

          setSnapshot({
            ...parsedData,
            positionRatio: parsedData.positionRatio || 0, 
            holdings: holdingsWithHorizon,
            date: new Date().toISOString().split('T')[0] 
          });
        } catch (err: any) {
          setError(`识别失败: ${err.message || "未知错误"}`);
        } finally {
          setParsing(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setParsing(false);
      setError("文件读取失败");
    }
  };

  // --- Handlers: Editing ---
  const startEdit = (index: number, item: HoldingItemDetailed) => {
    setEditingIndex(index);
    setEditForm({ ...item, horizon: item.horizon || 'medium' });
  };

  const saveEdit = () => {
    if (editForm && editingIndex !== null) {
      const newHoldings = [...snapshot.holdings];
      if (!editForm.marketValue || editForm.marketValue === 0) {
        editForm.marketValue = (editForm.volume || 0) * (editForm.currentPrice || 0);
      }
      newHoldings[editingIndex] = editForm;
      setSnapshot(prev => ({ ...prev, holdings: newHoldings }));
      setEditingIndex(null);
      setEditForm(null);
    }
  };

  const deleteHolding = (index: number) => {
    const newHoldings = [...snapshot.holdings];
    newHoldings.splice(index, 1);
    setSnapshot(prev => ({ ...prev, holdings: newHoldings }));
  };

  const addEmptyHolding = () => {
    setSnapshot(prev => ({
      ...prev,
      holdings: [...prev.holdings, {
        name: "新标的",
        code: "",
        volume: 0,
        costPrice: 0,
        currentPrice: 0,
        profit: 0,
        profitRate: "0%",
        marketValue: 0,
        horizon: 'short'
      }]
    }));
    setEditingIndex(snapshot.holdings.length);
    setEditForm({
        name: "新标的",
        code: "",
        volume: 0,
        costPrice: 0,
        currentPrice: 0,
        profit: 0,
        profitRate: "0%",
        marketValue: 0,
        horizon: 'short'
    });
  };

  // --- Handlers: Analysis ---
  const handleAnalyze = async () => {
    if (snapshot.holdings.length === 0) {
      setError("持仓列表为空，请先添加持仓");
      return;
    }

    setLoading(true);
    setAnalysisResult(null);
    setPeriodicResult(null);
    setError(null);
    setActiveTab('report'); 

    const marketLabel = MARKET_OPTIONS.find(m => m.value === currentMarket)?.label || currentMarket;

    const now = new Date();
    const todayFullStr = now.toLocaleString('zh-CN');
    const currentYear = now.getFullYear();

    const lastSessionEntry = journal.length > 0 ? journal[0] : null;

    let historyContext = "这是该账户的首次复盘分析。";

    if (lastSessionEntry) {
      const lastSessionTime = new Date(lastSessionEntry.timestamp).toLocaleString('zh-CN');
      historyContext = `
      【历史记录对比】
      - 历史最近快照: ${lastSessionTime}
      - 历史资产: ${lastSessionEntry.snapshot.totalAssets} 元
      - 历史建议回顾: ${lastSessionEntry.analysis?.content?.substring(0, 500)}
      `;
    }

    const currentHoldingsText = snapshot.holdings.map((h, i) => {
      const marketVal = (h.volume || 0) * (h.currentPrice || 0);
      const weight = snapshot.totalAssets > 0 ? ((marketVal / snapshot.totalAssets) * 100).toFixed(2) : "0.00";
      return `${i+1}. ${h.name} (${h.code}): 持仓${h.volume}, 成本${h.costPrice}, 盈亏率:${h.profitRate}, 占比:${weight}%`;
    }).join('\n');

    const prompt = `
      你是一位毒舌但极其专业的【私人基金经理】。请基于现实时间 ${todayFullStr} 进行 A 股持仓审计。

      [!!! 核心指令：严禁误判杠杆 !!!]
      - 用户可能持有“利润底仓”，其账面成本可能为负数或极低。这是高抛低吸做T成功后的结果。
      - **绝对严禁**因为看到持仓占比高或成本为负就声称用户“使用了高杠杆”。
      - 除非你从公开公告中查到该标的有大额质押风险，否则不得随意提及“强制平仓风险”。

      复盘任务：
      1. 审计账户执行力。
      2. 诊断个股技术周期：覆盖所有持仓标的，给出止盈止损建议位。
      3. 仓位管理：根据目前的 ${snapshot.positionRatio}% 仓位给出后续攻守节奏。

      === 账户详情 ===
      总资产: ${snapshot.totalAssets} 元 | 仓位: ${snapshot.positionRatio}%
      持仓列表:
      ${currentHoldingsText}

      ${historyContext}
    `;

    try {
      const result = await analyzeWithLLM(currentModel, prompt, true, settings, false, 'day', undefined, currentMarket);
      setAnalysisResult(result);
    } catch (err: any) {
      setError(err.message || "分析失败");
    } finally {
      setLoading(false);
    }
  };

  // --- Handlers: Plan Generation ---
  const handleGeneratePlan = async () => {
    if (!analysisResult) return;
    setGeneratingPlan(true);

    try {
      const { items, summary } = await extractTradingPlan(analysisResult.content, settings.geminiKey);

      const newPlan: DailyTradingPlan = {
        id: crypto.randomUUID(),
        target_date: new Date(Date.now() + 86400000).toISOString().split('T')[0], 
        created_at: Date.now(),
        items: items,
        strategy_summary: summary
      };

      setTradingPlans(prev => [newPlan, ...prev]);
      setIsPlanOpen(true);
    } catch (err: any) {
      setError("生成交易计划失败");
    } finally {
      setGeneratingPlan(false);
    }
  };

  const togglePlanItemStatus = (planId: string, itemId: string) => {
    setTradingPlans(prev => prev.map(p => {
       if (p.id !== planId) return p;
       return {
         ...p,
         items: p.items.map(item => {
           if (item.id !== itemId) return item;
           const states = ['pending', 'completed', 'skipped', 'failed'];
           const nextIndex = (states.indexOf(item.status) + 1) % states.length;
           return { ...item, status: states[nextIndex] as any };
         })
       };
    }));
  };

  const deletePlan = (planId: string) => {
    if (confirm("确定删除该交易计划？")) {
       setTradingPlans(prev => prev.filter(p => p.id !== planId));
    }
  };

  // --- Handlers: Export/Periodic ... (Keep others same)
  const downloadFile = (content: string, filename: string, mimeType: string) => {
    const blob = new Blob([content], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleExportPlanMD = () => {
     let md = "# 我的交易计划归档\n\n";
     tradingPlans.forEach(plan => {
        md += `## ${plan.target_date} (策略: ${plan.strategy_summary})\n`;
        md += "| 标意 | 操作 | 目标价 | 逻辑 | 状态 |\n";
        md += "| --- | --- | --- | --- | --- |\n";
        plan.items.forEach(item => {
           md += `| ${item.symbol} | ${item.action} | ${item.price_target || '--'} | ${item.reason} | ${item.status} |\n`;
        });
        md += "\n";
     });
     downloadFile(md, `TradingPlans_${new Date().toISOString().split('T')[0]}.md`, 'text/markdown');
  };

  const handleExportReportMD = (result: AnalysisResult | null) => {
    if (!result) return;
    const content = `# QuantMind 智能复盘报告\n\n${result.content}`;
    downloadFile(content, `Report_${new Date().toISOString().split('T')[0]}.md`, 'text/markdown');
  };

  const handlePeriodicReview = async (period: 'week' | 'month' | 'all') => {
    if (journal.length < 1) {
      setError("数据不足，无法生成总结");
      return;
    }
    setLoading(true);
    setPeriodicResult(null);
    setActiveTab('periodic');
    try {
      const result = await fetchPeriodicReview(journal, period, currentMarket, settings.geminiKey);
      setPeriodicResult(result);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const saveToJournal = () => {
    if (!analysisResult) return;
    const newEntry: JournalEntry = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      snapshot: { ...snapshot },
      analysis: analysisResult
    };
    setJournal(prev => [newEntry, ...prev]);
    alert("已入库历史日志");
  };

  const deleteJournalEntry = (id: string, e: React.MouseEvent) => {
    e.stopPropagation(); 
    if (confirm("永久删除？")) {
      setJournal(prev => prev.filter(entry => entry.id !== id));
    }
  };

  const loadEntry = (entry: JournalEntry) => {
    setSnapshot(entry.snapshot);
    setAnalysisResult(entry.analysis);
    setIsHistoryOpen(false);
  };

  // --- Pagination Logic ---
  const totalHistoryPages = Math.ceil(journal.length / HISTORY_PAGE_SIZE);
  const paginatedJournal = journal.slice((historyPage - 1) * HISTORY_PAGE_SIZE, historyPage * HISTORY_PAGE_SIZE);

  return (
    <div className="space-y-6 animate-fade-in pb-20">
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 no-print">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
          <div>
            <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
              <UploadCloud className="w-6 h-6 text-indigo-600" />
              智能持仓复盘 (Portfolio Review)
            </h2>
          </div>
          <div className="flex gap-2">
            <button onClick={() => setIsPlanOpen(!isPlanOpen)} className="flex items-center gap-2 px-3 py-2 text-sm font-medium text-slate-600 bg-slate-100 hover:bg-slate-200 rounded-lg border border-slate-200"><ListTodo className="w-4 h-4" />交易计划</button>
            <button onClick={() => setIsHistoryOpen(!isHistoryOpen)} className="flex items-center gap-2 px-3 py-2 text-sm font-medium text-slate-600 bg-slate-100 hover:bg-slate-200 rounded-lg border border-slate-200"><History className="w-4 h-4" />历史日志</button>
            <input type="file" accept="image/*" ref={fileInputRef} className="hidden" onChange={handleImageUpload} />
            <button onClick={() => fileInputRef.current?.click()} disabled={parsing} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg font-medium shadow-md">
              {parsing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Camera className="w-4 h-4" />}
              {parsing ? '智能提取中...' : '上传持仓截图'}
            </button>
          </div>
        </div>

        {isHistoryOpen && (
          <div className="mb-6 p-4 bg-slate-50 rounded-lg border border-slate-200 animate-slide-down">
            <h3 className="font-bold text-slate-700 mb-4">交易日志归档</h3>
            {journal.length === 0 ? (
              <p className="text-sm text-slate-400 text-center py-6">暂无历史日志</p>
            ) : (
              <div className="space-y-2 mb-4">
                {paginatedJournal.map((entry) => (
                   <div key={entry.id} onClick={() => loadEntry(entry)} className="p-3 bg-white rounded border border-slate-200 hover:border-indigo-400 cursor-pointer transition-all flex justify-between items-center group">
                      <div className="text-sm font-bold text-slate-800">
                        {new Date(entry.timestamp).toLocaleString()}
                        <span className="ml-3 text-xs font-normal text-slate-400">资产: ¥{entry.snapshot.totalAssets.toLocaleString()}</span>
                      </div>
                      <button onClick={(e) => deleteJournalEntry(entry.id, e)} className="p-1.5 text-slate-300 hover:text-rose-600 opacity-0 group-hover:opacity-100 transition-all"><Trash2 className="w-4 h-4" /></button>
                   </div>
                ))}
              </div>
            )}
          </div>
        )}

        {error && (
          <div className="mb-6 p-4 bg-red-50 border border-red-100 rounded-lg flex items-center text-red-700 gap-2 animate-fade-in">
            <AlertTriangle className="w-5 h-5 shrink-0" />
            <span className="text-sm font-bold">{error}</span>
          </div>
        )}

        <div className="overflow-x-auto rounded-lg border border-slate-200 mb-6">
           <div className="bg-slate-50 px-4 py-3 border-b border-slate-200 flex justify-between items-center">
              <div className="flex items-center gap-6">
                 <div className="flex flex-col">
                   <span className="text-[10px] text-slate-400 font-bold uppercase">总资产 (ASSETS)</span>
                   <div className="flex items-baseline gap-1">
                      <span className="font-bold text-slate-900">¥</span>
                      <input type="number" value={snapshot.totalAssets} onChange={(e) => setSnapshot({...snapshot, totalAssets: parseFloat(e.target.value) || 0})} className="bg-transparent border-b border-dashed border-slate-300 w-24 font-bold text-lg focus:outline-none"/>
                   </div>
                 </div>
                 <div className="flex flex-col">
                   <span className="text-[10px] text-slate-400 font-bold uppercase">仓位占比 (POS %)</span>
                   <div className="flex items-baseline gap-1">
                      <input type="number" value={snapshot.positionRatio || 0} onChange={(e) => setSnapshot({...snapshot, positionRatio: parseFloat(e.target.value) || 0})} className="bg-transparent border-b border-dashed border-slate-300 w-12 font-bold text-lg text-indigo-600 focus:outline-none text-center"/>
                      <span className="font-bold text-indigo-600">%</span>
                   </div>
                 </div>
                 <div className="text-[10px] text-slate-300 font-bold">日期: {snapshot.date}</div>
              </div>
              <button onClick={addEmptyHolding} className="text-xs font-bold text-indigo-600 hover:text-indigo-700">+ 添加标的</button>
           </div>

           <table className="w-full text-sm text-left">
              <thead className="bg-slate-50 text-slate-400 font-bold text-[10px] uppercase tracking-wider">
                 <tr>
                    <th className="px-4 py-3">标的名称 (代码)</th>
                    <th className="px-4 py-3 text-center">持仓量</th>
                    <th className="px-4 py-3 text-center">成本价</th>
                    <th className="px-4 py-3 text-center">现价</th>
                    <th className="px-4 py-3 text-center">盈亏</th>
                    <th className="px-4 py-3 text-right">操作</th>
                 </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                 {snapshot.holdings?.length === 0 ? (
                   <tr><td colSpan={6} className="text-center py-12 text-slate-300 font-bold">请上传截图或手动添加持仓</td></tr>
                 ) : snapshot.holdings?.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                       {editingIndex === idx && editForm ? (
                          <>
                            <td className="px-4 py-2">
                              <input className="w-full p-1 border rounded text-xs mb-1 block" value={editForm.name} onChange={e => setEditForm({...editForm, name: e.target.value})} placeholder="名称"/>
                              <input className="w-full p-1 border rounded text-xs font-mono" value={editForm.code} onChange={e => setEditForm({...editForm, code: e.target.value})} placeholder="代码"/>
                            </td>
                            <td className="px-4 py-2"><input type="number" className="w-full p-1 border rounded text-center" value={editForm.volume} onChange={e => setEditForm({...editForm, volume: parseFloat(e.target.value)})} /></td>
                            <td className="px-4 py-2"><input type="number" className="w-full p-1 border rounded text-center" value={editForm.costPrice} onChange={e => setEditForm({...editForm, costPrice: parseFloat(e.target.value)})} /></td>
                            <td className="px-4 py-2"><input type="number" className="w-full p-1 border rounded text-center" value={editForm.currentPrice} onChange={e => setEditForm({...editForm, currentPrice: parseFloat(e.target.value)})} /></td>
                            <td className="px-4 py-2 text-slate-400 text-xs text-center">自动计算</td>
                            <td className="px-4 py-2 text-right flex justify-end gap-1">
                               <button onClick={saveEdit} className="p-1.5 text-green-600 hover:bg-green-50 rounded transition-all"><Check className="w-4 h-4"/></button>
                               <button onClick={() => setEditingIndex(null)} className="p-1.5 text-slate-400 hover:bg-slate-100 rounded transition-all"><X className="w-4 h-4"/></button>
                            </td>
                          </>
                       ) : (
                          <>
                            <td className="px-4 py-3">
                               <div className="font-bold text-slate-800">{item.name}</div>
                               <div className="text-[10px] font-mono text-slate-400 mt-0.5">{item.code}</div>
                            </td>
                            <td className="px-4 py-3 text-slate-600 text-center">{item.volume}</td>
                            <td className="px-4 py-3 text-slate-600 text-center">{item.costPrice}</td>
                            <td className="px-4 py-3 font-bold text-slate-800 text-center">{item.currentPrice}</td>
                            <td className="px-4 py-3 text-center">
                               <div className={`font-black ${item.profit >= 0 ? 'text-red-500' : 'text-green-600'}`}>
                                  {item.profitRate}
                               </div>
                            </td>
                            <td className="px-4 py-3 text-right flex justify-end gap-2 no-print">
                               <button onClick={() => startEdit(idx, item)} className="p-1.5 text-slate-300 hover:text-indigo-600 hover:bg-indigo-50 rounded transition-all"><Edit2 className="w-4 h-4" /></button>
                               <button onClick={() => deleteHolding(idx)} className="p-1.5 text-slate-300 hover:text-rose-600 hover:bg-rose-50 rounded transition-all"><Trash2 className="w-4 h-4" /></button>
                            </td>
                          </>
                       )}
                    </tr>
                 ))}
              </tbody>
           </table>
        </div>

        <div className="flex justify-end gap-3 border-t border-slate-100 pt-6">
           <button onClick={() => handlePeriodicReview('month')} disabled={loading || journal.length < 2} className="px-4 py-2 text-sm font-bold text-slate-500 bg-slate-50 hover:bg-slate-100 rounded-lg disabled:opacity-50">生成月度总结</button>
           <button onClick={handleAnalyze} disabled={loading || snapshot.holdings?.length === 0} className="px-8 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold shadow-lg shadow-indigo-100 transition-all flex items-center gap-2 disabled:opacity-50">
             {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <TrendingUp className="w-4 h-4" />}
             开始深度复盘
           </button>
        </div>
      </div>

      {(analysisResult || periodicResult) && (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden animate-slide-up">
           <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex justify-between items-center no-print">
              <div className="flex gap-4">
                <button onClick={() => setActiveTab('report')} className={`px-4 py-2 text-sm font-bold rounded-lg transition-all ${activeTab === 'report' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}>AI 复盘报告</button>
              </div>
              <div className="flex gap-2">
                <button onClick={() => handleExportReportMD(analysisResult)} className="px-3 py-1.5 text-xs font-bold text-slate-500 bg-white border border-slate-200 rounded-lg hover:bg-slate-50"><FileText className="w-4 h-4" /></button>
                <button onClick={saveToJournal} className="px-4 py-1.5 text-sm font-bold text-indigo-600 bg-indigo-50 hover:bg-indigo-100 rounded-lg">存入复盘日志</button>
              </div>
           </div>
           <div className="p-6">
             {activeTab === 'report' && analysisResult && (
               <div className="prose prose-slate max-w-none">
                  {analysisResult.content.split('\n').map((line, i) => (
                    <p key={i} className="mb-2 leading-relaxed text-slate-700" dangerouslySetInnerHTML={{ __html: line.replace(/\*\*(.*?)\*\*/g, '<strong class="text-slate-900">$1</strong>') }} />
                  ))}
               </div>
             )}
           </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { ModelProvider, AnalysisResult, UserSettings, MarketType, HoldingsSnapshot, HoldingItemDetailed, JournalEntry, PeriodicReviewData, DailyTradingPlan, PlanItem } from '../types';
import { analyzeWithLLM } from '../services/llmAdapter';
import { parseBrokerageScreenshot, fetchPeriodicReview, extractTradingPlan } from '../services/geminiService';
import { analyzeImageWithExternal } from '../services/externalLlmService';
import { Upload, Loader2, Save, Download, UploadCloud, History, Trash2, Camera, Edit2, Check, X, FileJson, TrendingUp, AlertTriangle, PieChart as PieChartIcon, Activity, Target, ClipboardList, BarChart3, Crosshair, GitCompare, Clock, LineChart as LineChartIcon, Calendar, Trophy, AlertOctagon, CheckCircle2, XCircle, ArrowRightCircle, ListTodo, MoreHorizontal, Square, CheckSquare, FileText, FileSpreadsheet, FileCode, ChevronLeft, ChevronRight, AlertCircle, Scale, Coins, ShieldAlert, Microscope, MessageSquareQuote, Lightbulb, FileType, BookOpenCheck } from 'lucide-react';
import { MARKET_OPTIONS } from '../constants';
import { PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, ReferenceLine, LineChart, Line } from 'recharts';

interface HoldingsReviewProps {
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: UserSettings;
  onOpenSettings?: () => void;
}

const HISTORY_PAGE_SIZE = 5;

export const HoldingsReview: React.FC<HoldingsReviewProps> = ({
  currentModel,
  currentMarket,
  settings,
  onOpenSettings
}) => {
  // --- State ---
  const [snapshot, setSnapshot] = useState<HoldingsSnapshot>({
    totalAssets: 0,
    positionRatio: 0, 
    date: new Date().toISOString().split('T')[0],
    holdings: []
  });

  const [journal, setJournal] = useState<JournalEntry[]>(() => {
    const saved = localStorage.getItem('qm_journal');
    if (!saved) return [];
    try {
      const parsed = JSON.parse(saved);
      return (Array.isArray(parsed) ? parsed : []).map(item => ({
        ...item,
        id: item.id || `legacy-${item.timestamp}-${Math.random().toString(36).substr(2, 9)}`
      }));
    } catch (e) {
      return [];
    }
  });

  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [parsing, setParsing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Drawers
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [historyPage, setHistoryPage] = useState(1);
  const [activeTab, setActiveTab] = useState<'report' | 'periodic'>('report');

  // Periodic Review State
  const [periodicResult, setPeriodicResult] = useState<AnalysisResult | null>(null);

  // Editing State
  const [editingIndex, setEditingIndex] = useState<number | null>(null);
  const [editForm, setEditForm] = useState<HoldingItemDetailed | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);

  // --- Effects ---
  useEffect(() => {
    localStorage.setItem('qm_journal', JSON.stringify(journal));
  }, [journal]);

  // --- Handlers: Screenshot ---
  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const geminiSubModel = settings?.preferredGeminiModel === 'pro' 
      ? 'gemini-3-pro-preview' 
      : 'gemini-3-flash-preview';

    setParsing(true);
    setError(null);

    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = (reader.result as string).split(',')[1];
        try {
          let parsedData: HoldingsSnapshot;
          if (currentModel === ModelProvider.HUNYUAN_CN) {
             parsedData = await analyzeImageWithExternal(ModelProvider.HUNYUAN_CN, base64String, settings.hunyuanKey!);
          } else {
             parsedData = await parseBrokerageScreenshot(base64String, settings.geminiKey, geminiSubModel);
          }

          const safeHoldings = parsedData.holdings || [];
          setSnapshot({
            ...parsedData,
            positionRatio: parsedData.positionRatio || 0, 
            holdings: safeHoldings.map(h => ({ ...h, horizon: 'medium' })),
            date: new Date().toISOString().split('T')[0] 
          });
        } catch (err: any) {
          setError(`识别失败: ${err.message || "未知错误"}`);
        } finally {
          setParsing(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setParsing(false);
      setError("文件读取失败");
    }
  };

  // --- Handlers: Data Backup ---
  const handleExportJournal = () => {
    const data = JSON.stringify(journal, null, 2);
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `QuantMind_Journal_Backup_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleImportJournal = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const imported = JSON.parse(event.target?.result as string);
        if (Array.isArray(imported)) {
          if (confirm(`检测到 ${imported.length} 条记录，是否覆盖当前日志？`)) {
            setJournal(imported);
            alert("导入成功");
          }
        }
      } catch (e) {
        alert("无效的备份文件");
      }
    };
    reader.readAsText(file);
  };

  // --- Handlers: Analysis ---
  const handleAnalyze = async () => {
    if (snapshot.holdings.length === 0) {
      setError("持仓列表为空，请先添加持仓");
      return;
    }
    setLoading(true);
    setAnalysisResult(null);
    setError(null);
    setActiveTab('report'); 

    const currentHoldingsText = snapshot.holdings.map((h, i) => {
      const marketVal = (h.volume || 0) * (h.currentPrice || 0);
      return `${i+1}. ${h.name} (${h.code}): 持仓${h.volume}, 成本${h.costPrice}, 现价${h.currentPrice}, 盈亏率:${h.profitRate}`;
    }).join('\n');

    const prompt = `你是一位毒舌但专业的基金经理。请基于以下持仓进行审计：\n${currentHoldingsText}\n总资产: ${snapshot.totalAssets}, 仓位: ${snapshot.positionRatio}%。请重点核验“利润底仓（负成本）”逻辑。`;

    try {
      const result = await analyzeWithLLM(currentModel, prompt, true, settings, false, 'day', undefined, currentMarket);
      setAnalysisResult(result);
    } catch (err: any) {
      setError(err.message || "分析失败");
    } finally {
      setLoading(false);
    }
  };

  const handlePeriodicReview = async (period: 'week' | 'month' | 'all') => {
    if (journal.length < 1) {
      setError("数据不足，无法生成总结");
      return;
    }
    setLoading(true);
    setPeriodicResult(null);
    setActiveTab('periodic');
    try {
      const result = await fetchPeriodicReview(journal, period === 'week' ? '本周' : '本月', currentMarket, settings.geminiKey);
      setPeriodicResult(result);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const saveToJournal = () => {
    if (!analysisResult) return;
    const newEntry: JournalEntry = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      snapshot: { ...snapshot },
      analysis: analysisResult
    };
    setJournal(prev => [newEntry, ...prev]);
    alert("已入库历史日志");
  };

  const totalHistoryPages = Math.ceil(journal.length / HISTORY_PAGE_SIZE);
  const paginatedJournal = journal.slice((historyPage - 1) * HISTORY_PAGE_SIZE, historyPage * HISTORY_PAGE_SIZE);

  return (
    <div className="space-y-6 animate-fade-in pb-20">
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 no-print">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
          <div>
            <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
              <UploadCloud className="w-6 h-6 text-indigo-600" />
              智能持仓复盘 (Portfolio Review)
            </h2>
          </div>
          <div className="flex gap-2">
            <button onClick={() => setIsHistoryOpen(!isHistoryOpen)} className="flex items-center gap-2 px-3 py-2 text-sm font-black text-slate-600 bg-slate-100 hover:bg-slate-200 rounded-lg border border-slate-200"><History className="w-4 h-4" />历史日志</button>
            <input type="file" accept="image/*" ref={fileInputRef} className="hidden" onChange={handleImageUpload} />
            <button onClick={() => fileInputRef.current?.click()} disabled={parsing} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-black shadow-md">
              {parsing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Camera className="w-4 h-4" />}
              {parsing ? '提取中...' : '上传持仓图'}
            </button>
          </div>
        </div>

        {isHistoryOpen && (
          <div className="mb-6 p-5 bg-slate-50 rounded-xl border border-slate-200 animate-slide-down">
            <div className="flex justify-between items-center mb-4">
              <h3 className="font-black text-slate-700 flex items-center gap-2"><BookOpenCheck className="w-4 h-4" /> 交易日志归档</h3>
              <div className="flex gap-2">
                 <button onClick={handleExportJournal} className="text-xs font-bold text-indigo-600 flex items-center gap-1 hover:underline"><Download className="w-3.5 h-3.5"/> 导出备份 (JSON)</button>
                 <button onClick={() => importInputRef.current?.click()} className="text-xs font-bold text-slate-500 flex items-center gap-1 hover:underline"><Upload className="w-3.5 h-3.5"/> 导入历史</button>
                 <input type="file" ref={importInputRef} className="hidden" accept=".json" onChange={handleImportJournal} />
              </div>
            </div>
            {journal.length === 0 ? (
              <p className="text-sm text-slate-400 text-center py-6">暂无历史日志</p>
            ) : (
              <div className="space-y-2">
                {paginatedJournal.map((entry) => (
                   <div key={entry.id} onClick={() => {setSnapshot(entry.snapshot); setAnalysisResult(entry.analysis); setIsHistoryOpen(false);}} className="p-3 bg-white rounded-lg border border-slate-200 hover:border-indigo-400 cursor-pointer transition-all flex justify-between items-center group">
                      <div className="text-sm font-black text-slate-800">
                        {new Date(entry.timestamp).toLocaleString()}
                        <span className="ml-3 text-xs font-normal text-slate-400">资产: ¥{entry.snapshot.totalAssets.toLocaleString()}</span>
                      </div>
                      <button onClick={(e) => {e.stopPropagation(); setJournal(prev => prev.filter(j => j.id !== entry.id));}} className="p-1.5 text-slate-300 hover:text-rose-600 opacity-0 group-hover:opacity-100 transition-all"><Trash2 className="w-4 h-4" /></button>
                   </div>
                ))}
                {totalHistoryPages > 1 && (
                  <div className="flex justify-center gap-2 mt-4">
                    <button disabled={historyPage === 1} onClick={() => setHistoryPage(p => p - 1)} className="p-1 disabled:opacity-30"><ChevronLeft className="w-5 h-5"/></button>
                    <span className="text-xs font-black self-center">{historyPage} / {totalHistoryPages}</span>
                    <button disabled={historyPage === totalHistoryPages} onClick={() => setHistoryPage(p => p + 1)} className="p-1 disabled:opacity-30"><ChevronRight className="w-5 h-5"/></button>
                  </div>
                )}
              </div>
            )}
          </div>
        )}

        {error && (
          <div className="mb-6 p-4 bg-red-50 border border-red-100 rounded-lg flex items-center text-red-700 gap-2">
            <AlertTriangle className="w-5 h-5 shrink-0" />
            <span className="text-sm font-black">{error}</span>
          </div>
        )}

        <div className="overflow-x-auto rounded-xl border border-slate-200 mb-6">
           <div className="bg-slate-50 px-4 py-3 border-b border-slate-200 flex justify-between items-center">
              <div className="flex items-center gap-6">
                 <div className="flex flex-col">
                   <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">总资产 (ASSETS)</span>
                   <div className="flex items-baseline gap-1">
                      <span className="font-black text-slate-900">¥</span>
                      <input type="number" value={snapshot.totalAssets} onChange={(e) => setSnapshot({...snapshot, totalAssets: parseFloat(e.target.value) || 0})} className="bg-transparent border-b border-dashed border-slate-300 w-32 font-black text-xl focus:outline-none"/>
                   </div>
                 </div>
                 <div className="flex flex-col">
                   <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">仓位占比 (POS %)</span>
                   <div className="flex items-baseline gap-1">
                      <input type="number" value={snapshot.positionRatio || 0} onChange={(e) => setSnapshot({...snapshot, positionRatio: parseFloat(e.target.value) || 0})} className="bg-transparent border-b border-dashed border-slate-300 w-12 font-black text-xl text-indigo-600 focus:outline-none text-center"/>
                      <span className="font-black text-indigo-600">%</span>
                   </div>
                 </div>
              </div>
              <button onClick={() => setSnapshot(prev => ({...prev, holdings: [...prev.holdings, {name: "新标的", code: "", volume: 0, costPrice: 0, currentPrice: 0, profit: 0, profitRate: "0%", marketValue: 0}]}))} className="text-xs font-black text-indigo-600 hover:text-indigo-700">+ 手动添加标的</button>
           </div>

           <table className="w-full text-sm text-left">
              <thead className="bg-slate-50 text-slate-400 font-black text-[10px] uppercase tracking-wider">
                 <tr>
                    <th className="px-4 py-3">标的名称 (代码)</th>
                    <th className="px-4 py-3 text-center">持仓量</th>
                    <th className="px-4 py-3 text-center">成本价</th>
                    <th className="px-4 py-3 text-center">现价</th>
                    <th className="px-4 py-3 text-center">盈亏率</th>
                    <th className="px-4 py-3 text-right">操作</th>
                 </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                 {snapshot.holdings?.length === 0 ? (
                   <tr><td colSpan={6} className="text-center py-12 text-slate-300 font-black">请上传截图或手动录入持仓数据</td></tr>
                 ) : snapshot.holdings?.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                       <td className="px-4 py-3">
                          <div className="font-black text-slate-800">{item.name}</div>
                          <div className="text-[10px] font-mono text-slate-400 mt-0.5">{item.code}</div>
                       </td>
                       <td className="px-4 py-3 text-slate-600 text-center font-bold">{item.volume}</td>
                       <td className="px-4 py-3 text-slate-600 text-center font-bold">{item.costPrice}</td>
                       <td className="px-4 py-3 font-black text-slate-800 text-center">{item.currentPrice}</td>
                       <td className={`px-4 py-3 text-center font-black ${item.profitRate?.includes('-') ? 'text-emerald-600' : 'text-rose-600'}`}>
                          {item.profitRate}
                       </td>
                       <td className="px-4 py-3 text-right">
                          <button onClick={() => setSnapshot(prev => ({...prev, holdings: prev.holdings.filter((_, i) => i !== idx)}))} className="p-1.5 text-slate-300 hover:text-rose-600 transition-all"><Trash2 className="w-4 h-4" /></button>
                       </td>
                    </tr>
                 ))}
              </tbody>
           </table>
        </div>

        <div className="flex justify-end gap-3 border-t border-slate-100 pt-6">
           <button onClick={() => handlePeriodicReview('week')} disabled={loading || journal.length < 2} className="px-4 py-2 text-sm font-black text-indigo-600 bg-indigo-50 hover:bg-indigo-100 rounded-lg disabled:opacity-50">周度深度总结</button>
           <button onClick={() => handlePeriodicReview('month')} disabled={loading || journal.length < 2} className="px-4 py-2 text-sm font-black text-slate-500 bg-slate-50 hover:bg-slate-100 rounded-lg disabled:opacity-50">月度数据审计</button>
           <button onClick={handleAnalyze} disabled={loading || snapshot.holdings?.length === 0} className="px-8 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-black shadow-lg shadow-indigo-100 transition-all flex items-center gap-2 disabled:opacity-50">
             {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <TrendingUp className="w-4 h-4" />}
             开始深度复盘分析
           </button>
        </div>
      </div>

      {(analysisResult || periodicResult) && (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden animate-slide-up">
           <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex justify-between items-center no-print">
              <div className="flex gap-4">
                <button onClick={() => setActiveTab('report')} className={`px-4 py-2 text-sm font-black rounded-lg transition-all ${activeTab === 'report' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}>AI 复盘报告</button>
                {periodicResult && <button onClick={() => setActiveTab('periodic')} className={`px-4 py-2 text-sm font-black rounded-lg transition-all ${activeTab === 'periodic' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}>周期总结面板</button>}
              </div>
              <div className="flex gap-2">
                <button onClick={saveToJournal} className="px-4 py-1.5 text-sm font-black text-indigo-600 bg-indigo-50 hover:bg-indigo-100 rounded-lg">存入复盘日志库</button>
              </div>
           </div>

           <div className="p-8">
             {activeTab === 'report' && analysisResult && (
               <div className="prose prose-slate max-w-none">
                  {analysisResult.content.split('\n').map((line, i) => (
                    <p key={i} className="mb-2 leading-relaxed text-slate-700 font-medium" dangerouslySetInnerHTML={{ __html: line.replace(/\*\*(.*?)\*\*/g, '<strong class="text-slate-900">$1</strong>') }} />
                  ))}
               </div>
             )}

             {activeTab === 'periodic' && periodicResult?.periodicData && (
                <div className="space-y-8">
                   <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      <div className="bg-indigo-600 rounded-[2rem] p-6 text-white text-center shadow-xl">
                         <div className="text-[10px] font-black uppercase tracking-widest opacity-60 mb-2">周期账户评分</div>
                         <div className="text-6xl font-black tracking-tighter">{periodicResult.periodicData.score}</div>
                         <div className="text-xs font-bold mt-2 bg-white/20 rounded-full py-1">状态：{periodicResult.periodicData.market_trend === 'bull' ? '上涨趋势' : '弱势震荡'}</div>
                      </div>
                      <div className="md:col-span-2 bg-slate-900 rounded-[2rem] p-8 text-white relative overflow-hidden">
                         <div className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-4">周期核心研判</div>
                         <p className="text-lg font-black italic leading-relaxed">"{periodicResult.periodicData.market_summary}"</p>
                         <div className="mt-6 flex gap-3">
                            <span className="px-3 py-1 bg-emerald-500/20 text-emerald-400 border border-emerald-500/30 rounded-lg text-xs font-black">执行力得分: {periodicResult.periodicData.execution.score}</span>
                         </div>
                      </div>
                   </div>

                   <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div className="p-6 rounded-3xl bg-emerald-50 border border-emerald-100">
                         <h4 className="font-black text-emerald-800 flex items-center gap-2 mb-4"><Trophy className="w-5 h-5"/> 操作亮点 (Highlights)</h4>
                         <ul className="space-y-3">
                            {periodicResult.periodicData.execution.good_behaviors?.map((b, i) => <li key={i} className="text-sm font-bold text-emerald-700 flex gap-2"><CheckCircle2 className="w-4 h-4 mt-0.5 shrink-0"/> {b}</li>)}
                         </ul>
                      </div>
                      <div className="p-6 rounded-3xl bg-rose-50 border border-rose-100">
                         <h4 className="font-black text-rose-800 flex items-center gap-2 mb-4"><ShieldAlert className="w-5 h-5"/> 执行力短板 (Execution Risk)</h4>
                         <ul className="space-y-3">
                            {periodicResult.periodicData.execution.bad_behaviors?.map((b, i) => <li key={i} className="text-sm font-bold text-rose-700 flex gap-2"><AlertTriangle className="w-4 h-4 mt-0.5 shrink-0"/> {b}</li>)}
                         </ul>
                      </div>
                   </div>

                   <div className="bg-white rounded-3xl border border-slate-200 p-8">
                      <h4 className="font-black text-slate-800 text-lg mb-6 flex items-center gap-2"><Microscope className="w-6 h-6 text-indigo-600"/> 持仓个股诊断建议</h4>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                         {periodicResult.periodicData.stock_diagnostics?.map((stock, i) => (
                            <div key={i} className="p-5 bg-slate-50 rounded-2xl border border-slate-100 group hover:border-indigo-400 transition-all">
                               <div className="font-black text-slate-900 mb-2">{stock.name}</div>
                               <div className="space-y-2 mb-3">
                                  {stock.issues?.map((issue, idx) => <div key={idx} className="text-[11px] font-bold text-slate-500 flex gap-1"><XCircle className="w-3 h-3 mt-0.5 text-rose-400"/> {issue}</div>)}
                               </div>
                               <div className="text-xs font-black text-indigo-600 bg-white p-3 rounded-xl border border-indigo-100 italic">“{stock.verdict}”</div>
                            </div>
                         ))}
                      </div>
                   </div>
                </div>
             )}
           </div>
        </div>
      )}
    </div>
  );
};
